editorial:
**Approach — doubly-linked list + hash map**: The DLL keeps recency order (head = most-recent, tail = least-recent). The map gives O(1) lookup `key → node`. On `get`, move the node to the head. On `put`, either update + move-to-head, or insert a new node at head and evict tail if over capacity.

```javascript
function runOps(ops) {
  class Node {
    constructor(k, v) { this.k = k; this.v = v; this.prev = null; this.next = null; }
  }
  class LRUCache {
    constructor(cap) {
      this.cap = cap;
      this.map = new Map();
      this.head = new Node(0, 0);
      this.tail = new Node(0, 0);
      this.head.next = this.tail;
      this.tail.prev = this.head;
    }
    _remove(node) {
      node.prev.next = node.next;
      node.next.prev = node.prev;
    }
    _addToFront(node) {
      node.next = this.head.next;
      node.prev = this.head;
      this.head.next.prev = node;
      this.head.next = node;
    }
    get(key) {
      if (!this.map.has(key)) return -1;
      const node = this.map.get(key);
      this._remove(node);
      this._addToFront(node);
      return node.v;
    }
    put(key, value) {
      if (this.map.has(key)) {
        const node = this.map.get(key);
        node.v = value;
        this._remove(node);
        this._addToFront(node);
        return;
      }
      if (this.map.size === this.cap) {
        const lru = this.tail.prev;
        this._remove(lru);
        this.map.delete(lru.k);
      }
      const node = new Node(key, value);
      this._addToFront(node);
      this.map.set(key, node);
    }
  }
  let cache = null;
  const out = [];
  for (const op of ops) {
    if (op[0] === 'LRUCache') { cache = new LRUCache(op[1]); out.push(null); }
    else if (op[0] === 'put') { cache.put(op[1], op[2]); out.push(null); }
    else if (op[0] === 'get') { out.push(cache.get(op[1])); }
  }
  return out;
}
```

**Time**: O(1) per op. **Space**: O(capacity).

Pro tip: JavaScript's `Map` already keeps insertion order, so you can skip the DLL entirely — `delete` + `set` reinserts at the back. But interviews expect the DLL for showing the data-structure design.

