editorial:
**Approach — three maps**: `keyToVal`, `keyToFreq`, and `freqToKeys` (each value is an insertion-ordered Set of keys at that freq). Maintain `minFreq` to know which bucket to evict from.

```javascript
function runOps(ops) {
  class LFUCache {
    constructor(cap) {
      this.cap = cap;
      this.size = 0;
      this.minFreq = 0;
      this.keyToVal = new Map();
      this.keyToFreq = new Map();
      this.freqToKeys = new Map();
    }
    _bump(key) {
      const f = this.keyToFreq.get(key);
      this.keyToFreq.set(key, f + 1);
      this.freqToKeys.get(f).delete(key);
      if (this.freqToKeys.get(f).size === 0) {
        this.freqToKeys.delete(f);
        if (this.minFreq === f) this.minFreq++;
      }
      if (!this.freqToKeys.has(f + 1)) this.freqToKeys.set(f + 1, new Set());
      this.freqToKeys.get(f + 1).add(key);
    }
    get(key) {
      if (!this.keyToVal.has(key)) return -1;
      this._bump(key);
      return this.keyToVal.get(key);
    }
    put(key, value) {
      if (this.cap === 0) return;
      if (this.keyToVal.has(key)) {
        this.keyToVal.set(key, value);
        this._bump(key);
        return;
      }
      if (this.size === this.cap) {
        const bucket = this.freqToKeys.get(this.minFreq);
        const evictKey = bucket.values().next().value;
        bucket.delete(evictKey);
        if (bucket.size === 0) this.freqToKeys.delete(this.minFreq);
        this.keyToVal.delete(evictKey);
        this.keyToFreq.delete(evictKey);
        this.size--;
      }
      this.keyToVal.set(key, value);
      this.keyToFreq.set(key, 1);
      if (!this.freqToKeys.has(1)) this.freqToKeys.set(1, new Set());
      this.freqToKeys.get(1).add(key);
      this.minFreq = 1;
      this.size++;
    }
  }
  let cache = null;
  const out = [];
  for (const op of ops) {
    if (op[0] === 'LFUCache') { cache = new LFUCache(op[1]); out.push(null); }
    else if (op[0] === 'put') { cache.put(op[1], op[2]); out.push(null); }
    else if (op[0] === 'get') { out.push(cache.get(op[1])); }
  }
  return out;
}
```

**Time**: O(1) amortized per op. **Space**: O(capacity).

Key insight: JS `Set` preserves insertion order — `values().next().value` gives the oldest entry, perfect for LRU-tiebreak inside a freq bucket.

