editorial:
**Approach — lazy transfer**: Keep two stacks. Pushing always goes to `inStack`. When `pop`/`peek` is called, if `outStack` is empty drain `inStack` into it (reverses order, so FIFO preserved). Each element migrates at most once, amortized O(1).

```javascript
function runOps(ops) {
  class MyQueue {
    constructor() { this.inS = []; this.outS = []; }
    push(x) { this.inS.push(x); }
    _shift() {
      if (this.outS.length === 0) {
        while (this.inS.length) this.outS.push(this.inS.pop());
      }
    }
    pop() { this._shift(); return this.outS.pop(); }
    peek() { this._shift(); return this.outS[this.outS.length - 1]; }
    empty() { return this.inS.length === 0 && this.outS.length === 0; }
  }
  let q = null;
  const out = [];
  for (const op of ops) {
    if (op[0] === 'MyQueue') { q = new MyQueue(); out.push(null); }
    else if (op[0] === 'push') { q.push(op[1]); out.push(null); }
    else if (op[0] === 'pop') { out.push(q.pop()); }
    else if (op[0] === 'peek') { out.push(q.peek()); }
    else if (op[0] === 'empty') { out.push(q.empty()); }
  }
  return out;
}
```

**Time**: amortized O(1). **Space**: O(n).

