editorial:
**Approach — separate chaining**: Fixed-size bucket array; each bucket is an array of keys. Hash = `key % B`. `add` skips if already present; `remove` linear-scans and splices.

```javascript
function runOps(ops) {
  class MyHashSet {
    constructor() {
      this.B = 1009;
      this.buckets = Array.from({ length: this.B }, () => []);
    }
    _h(k) { return k % this.B; }
    add(k) {
      const b = this.buckets[this._h(k)];
      if (!b.includes(k)) b.push(k);
    }
    remove(k) {
      const b = this.buckets[this._h(k)];
      const i = b.indexOf(k);
      if (i !== -1) b.splice(i, 1);
    }
    contains(k) {
      return this.buckets[this._h(k)].includes(k);
    }
  }
  let s = null;
  const out = [];
  for (const op of ops) {
    if (op[0] === 'MyHashSet') { s = new MyHashSet(); out.push(null); }
    else if (op[0] === 'add') { s.add(op[1]); out.push(null); }
    else if (op[0] === 'remove') { s.remove(op[1]); out.push(null); }
    else if (op[0] === 'contains') { out.push(s.contains(op[1])); }
  }
  return out;
}
```

**Time**: O(n/B) average per op. **Space**: O(n + B).

1009 prime — better key distribution. For very large n, resize when load factor crosses ~0.75.

