editorial:
**Approach**: Maintain a global timestamp counter. `tweets[userId]` is a list of `[ts, tweetId]`; `following[userId]` is a Set. `getNewsFeed` merges tweet lists from self + followees, sorts by ts desc, returns first 10.

```javascript
function runOps(ops) {
  class Twitter {
    constructor() {
      this.ts = 0;
      this.tweets = new Map();
      this.following = new Map();
    }
    postTweet(u, tw) {
      if (!this.tweets.has(u)) this.tweets.set(u, []);
      this.tweets.get(u).push([this.ts++, tw]);
    }
    follow(f, t) {
      if (!this.following.has(f)) this.following.set(f, new Set());
      this.following.get(f).add(t);
    }
    unfollow(f, t) {
      if (this.following.has(f)) this.following.get(f).delete(t);
    }
    getNewsFeed(u) {
      const ids = new Set([u]);
      if (this.following.has(u)) for (const v of this.following.get(u)) ids.add(v);
      const all = [];
      for (const v of ids) {
        if (this.tweets.has(v)) for (const t of this.tweets.get(v)) all.push(t);
      }
      all.sort((a, b) => b[0] - a[0]);
      return all.slice(0, 10).map(x => x[1]);
    }
  }
  let t = null;
  const out = [];
  for (const op of ops) {
    if (op[0] === 'Twitter') { t = new Twitter(); out.push(null); }
    else if (op[0] === 'postTweet') { t.postTweet(op[1], op[2]); out.push(null); }
    else if (op[0] === 'follow') { t.follow(op[1], op[2]); out.push(null); }
    else if (op[0] === 'unfollow') { t.unfollow(op[1], op[2]); out.push(null); }
    else if (op[0] === 'getNewsFeed') { out.push(t.getNewsFeed(op[1])); }
  }
  return out;
}
```

**Time**: O(N log N) per feed where N = total tweets across self+followees. With min-heap of size 10 you can get O(N log 10).
**Space**: O(tweets + follows).

