editorial:
**Approach — versioned writes per index**: For each index keep `[[snap_id, val], ...]` sorted by `snap_id`. `set(i, v)` appends `[curSnap, v]` (or overwrites the last if same `curSnap`). `snap()` increments and returns the previous counter. `get(i, sid)` binary-searches the largest `snap_id <= sid`; default 0.

```javascript
function runOps(ops) {
  class SnapshotArray {
    constructor(length) {
      this.length = length;
      this.cur = 0;
      this.data = Array.from({ length }, () => []);
    }
    set(i, v) {
      const arr = this.data[i];
      if (arr.length && arr[arr.length - 1][0] === this.cur) arr[arr.length - 1][1] = v;
      else arr.push([this.cur, v]);
    }
    snap() {
      return this.cur++;
    }
    get(i, sid) {
      const arr = this.data[i];
      let lo = 0, hi = arr.length - 1, ans = -1;
      while (lo <= hi) {
        const mid = (lo + hi) >> 1;
        if (arr[mid][0] <= sid) { ans = mid; lo = mid + 1; }
        else hi = mid - 1;
      }
      return ans === -1 ? 0 : arr[ans][1];
    }
  }
  let sa = null;
  const out = [];
  for (const op of ops) {
    if (op[0] === 'SnapshotArray') { sa = new SnapshotArray(op[1]); out.push(null); }
    else if (op[0] === 'set') { sa.set(op[1], op[2]); out.push(null); }
    else if (op[0] === 'snap') { out.push(sa.snap()); }
    else if (op[0] === 'get') { out.push(sa.get(op[1], op[2])); }
  }
  return out;
