**Approach — queue of timestamps**: Push every hit. On any operation, drop from the front while `front <= now - 300`. The remaining queue length is the answer.

```javascript
function runOps(ops) {
  class HitCounter {
    constructor() { this.q = []; }
    _evict(now) {
      while (this.q.length && this.q[0] <= now - 300) this.q.shift();
    }
    hit(ts) {
      this._evict(ts);
      this.q.push(ts);
    }
    getHits(ts) {
      this._evict(ts);
      return this.q.length;
    }
  }
  let hc = null;
  const out = [];
  for (const op of ops) {
    if (op[0] === 'HitCounter') { hc = new HitCounter(); out.push(null); }
    else if (op[0] === 'hit') { hc.hit(op[1]); out.push(null); }
    else if (op[0] === 'getHits') { out.push(hc.getHits(op[1])); }
  }
  return out;
}
```

**Time**: amortized O(1) per hit; getHits worst-case O(k) for k expired evictions but amortized O(1).
**Space**: O(hits in window).

