editorial:
**Approach — lazy refill**: On every `allow(now)`, first refill: `tokens = min(cap, tokens + (now - lastTs) * refillRate)` and set `lastTs = now`. Then if `tokens > 0`, decrement and return true; else false.

```javascript
function runOps(ops) {
  class RateLimiter {
    constructor(cap, rate) {
      this.cap = cap;
      this.rate = rate;
      this.tokens = cap;
      this.lastTs = -1;
    }
    allow(now) {
      if (this.lastTs === -1) {
        this.lastTs = now;
      } else {
        const refill = (now - this.lastTs) * this.rate;
        if (refill > 0) {
          this.tokens = Math.min(this.cap, this.tokens + refill);
          this.lastTs = now;
        }
      }
      if (this.tokens > 0) { this.tokens--; return true; }
      return false;
    }
  }
  let rl = null;
  const out = [];
  for (const op of ops) {
    if (op[0] === 'RateLimiter') { rl = new RateLimiter(op[1], op[2]); out.push(null); }
    else if (op[0] === 'allow') { out.push(rl.allow(op[1])); }
  }
  return out;
}
```

**Time**: O(1) per call. **Space**: O(1).

Note: only update `lastTs` when refill > 0, otherwise within-the-same-second multiple calls would accidentally never advance the clock. Here updating only on positive refill keeps the invariant clean.

