**Approach — two maps**: `pending: Map<id, [station, t]>` for in-progress trips. `stats: Map<"start→end", [sum, count]>` for completed trips. `getAverageTime` divides.

```javascript
function runOps(ops) {
  class UndergroundSystem {
    constructor() {
      this.pending = new Map();
      this.stats = new Map();
    }
    checkIn(id, st, t) { this.pending.set(id, [st, t]); }
    checkOut(id, st, t) {
      const [start, t0] = this.pending.get(id);
      this.pending.delete(id);
      const key = start + '\u0001' + st;
      const cur = this.stats.get(key) || [0, 0];
      cur[0] += (t - t0);
      cur[1] += 1;
      this.stats.set(key, cur);
    }
    getAverageTime(a, b) {
      const [sum, cnt] = this.stats.get(a + '\u0001' + b);
      return sum / cnt;
    }
  }
  let u = null;
  const out = [];
  for (const op of ops) {
    if (op[0] === 'UndergroundSystem') { u = new UndergroundSystem(); out.push(null); }
    else if (op[0] === 'checkIn') { u.checkIn(op[1], op[2], op[3]); out.push(null); }
    else if (op[0] === 'checkOut') { u.checkOut(op[1], op[2], op[3]); out.push(null); }
    else if (op[0] === 'getAverageTime') { out.push(u.getAverageTime(op[1], op[2])); }
  }
  return out;
}
```

**Time**: O(1) per op. **Space**: O(passengers + station-pairs).

Key detail: use a delimiter unlikely in station names (`\u0001`) for the composite key, so 'AB|C' and 'A|BC' don't collide.

